import org.apache.cxf.ws.security.wss4j.WSS4JOutInterceptor;
import org.apache.wss4j.common.crypto.Crypto;
import org.apache.wss4j.common.crypto.CryptoFactory;
import org.apache.wss4j.dom.WSConstants;
import org.apache.wss4j.dom.handler.WSHandlerConstants;

import javax.security.auth.callback.CallbackHandler;
import java.io.InputStream;
import java.util.HashMap;
import java.util.Map;
import java.util.Properties;

public class BankingTransactionsClientFactory {

    public static <T> T createSignedClient(Class<T> sei, String address, String cryptoPropsClasspath, String keyAlias, CallbackHandler passwordCallback) {
        JaxWsProxyFactoryBean pf = new JaxWsProxyFactoryBean();
        pf.setServiceClass(sei);
        pf.setAddress(address);
        @SuppressWarnings("unchecked")
        T proxy = (T) pf.create();

        Client client = ClientProxy.getClient(proxy);

        Map<String, Object> outProps = new HashMap<>();
        outProps.put(WSHandlerConstants.ACTION, WSHandlerConstants.SIGNATURE);
        outProps.put(WSHandlerConstants.USER, keyAlias);
        outProps.put(WSHandlerConstants.PW_CALLBACK_REF, passwordCallback);
        outProps.put(WSHandlerConstants.SIG_PROP_FILE, cryptoPropsClasspath);
        outProps.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");
        outProps.put(WSHandlerConstants.SIGNATURE_PARTS,
                "{Element}{" + WSConstants.URI_SOAP11_ENV + "}Body;" +
                        "{Element}{http://bank.example.com/transactions}TransactionRequest");

        client.getOutInterceptors().add(new WSS4JOutInterceptor(outProps));
        return proxy;
    }

    public static Crypto loadCrypto(String cryptoPropertiesClasspath) {
        try (InputStream is = Thread.currentThread().getContextClassLoader().getResourceAsStream(cryptoPropertiesClasspath)) {
            if (is == null) {
                throw new IllegalArgumentException("Crypto properties not found: " + cryptoPropertiesClasspath);
            }
            Properties props = new Properties();
            props.load(is);
            return CryptoFactory.getInstance(props);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}

package com.bank.ws.client;

import javax.security.auth.callback.Callback;
import javax.security.auth.callback.CallbackHandler;
import javax.security.auth.callback.UnsupportedCallbackException;
import java.io.IOException;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

import org.apache.wss4j.common.ext.WSPasswordCallback;

public class SimplePasswordCallback implements CallbackHandler {

    private final Map<String, String> passwords = new ConcurrentHashMap<>();

    public SimplePasswordCallback add(String alias, String password) {
        passwords.put(alias, password);
        return this;
    }

    @Override
    public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
        for (Callback cb : callbacks) {
            if (cb instanceof WSPasswordCallback) {
                WSPasswordCallback pc = (WSPasswordCallback) cb;
                String pw = passwords.get(pc.getIdentifier());
                if (pw != null) {
                    pc.setPassword(pw);
                }
            }
        }
    }
}

package com.bank.ws.util;

import org.w3c.dom.Element;
import org.w3c.dom.Node;

import javax.xml.transform.OutputKeys;
import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;
import java.io.StringWriter;

public final class XmlUtil {
    private XmlUtil() {}

    public static String toString(Node node) {
        try {
            TransformerFactory tf = TransformerFactory.newInstance();
            Transformer t = tf.newTransformer();
            t.setOutputProperty(OutputKeys.OMIT_XML_DECLARATION, "yes");
            t.setOutputProperty(OutputKeys.INDENT, "no");
            StringWriter sw = new StringWriter();
            t.transform(new DOMSource(node), new StreamResult(sw));
            return sw.toString();
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    public static boolean isElement(Node n, String ns, String local) {
        if (!(n instanceof Element)) return false;
        Element e = (Element) n;
        return local.equals(e.getLocalName()) && ns.equals(e.getNamespaceURI());
    }
}

